public interface ObjectDeserializer
        extends ObjectReader {
    @Override
    default Object readObject(JSONReader jsonReader, Type fieldType, Object fieldName, long features) {
        DefaultJSONParser parser = new DefaultJSONParser(jsonReader, ParserConfig.global);
        return deserialze(parser, fieldType, fieldName);
    }

    <T> T deserialze(DefaultJSONParser parser, Type type, Object fieldName);

    default int getFastMatchToken() {
        return JSONLexer.UNKNOWN;
    }
}

public interface ContextValueFilter
        extends com.alibaba.fastjson2.filter.ContextValueFilter, SerializeFilter {
    @Override
    default Object process(com.alibaba.fastjson2.filter.BeanContext context, Object object, String name, Object value) {
        return process(new com.alibaba.fastjson.serializer.BeanContext(context), object, name, value);
    }

    Object process(BeanContext context, Object object, String name, Object value);
}

public interface PropertyPreFilter
        extends com.alibaba.fastjson2.filter.PropertyPreFilter, SerializeFilter {
    default boolean process(JSONWriter writer, Object source, String name) {
        JSONSerializer serializer = JSONSerializer.getJSONSerializer(writer);
        serializer.setContext(new SerialContext(writer, serializer.context, source, name, 0, 0));
        return apply(serializer, source, name);
    }

    boolean apply(JSONSerializer serializer, Object object, String name);
}

@Configuration
public class AddressServerSecurityConfiguration {

    @Bean
    @Order(99)
    public SecurityFilterChain addressServerSecurityFilterChain(HttpSecurity http)
        throws Exception {
        http.authorizeHttpRequests(
            requestMatcherRegistry -> requestMatcherRegistry
                .requestMatchers("/nacos/v1/as/**").authenticated())
            .csrf(AbstractHttpConfigurer::disable)
            .httpBasic(Customizer.withDefaults());
        return http.build();
    }
}

